package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithFirstRecordAsHeader() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        Method withFirstRecordAsHeaderMethod = CSVFormat.class.getDeclaredMethod("withFirstRecordAsHeader");
        withFirstRecordAsHeaderMethod.setAccessible(true);
        CSVFormat result = (CSVFormat) withFirstRecordAsHeaderMethod.invoke(csvFormat);

        // Then
        assertTrue(result.getSkipHeaderRecord());
        assertNotNull(result.getHeader());
    }
}
